package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class LineItemTest {

  @Test
  void testToString() throws Exception {
    String name = "TestItem";
    int quantity = 5;
    long priceInMicros = 12345678L; // 12.345678 dollars
    String currencyCode = "USD";

    // Directly use the LineItem class instead of reflection to avoid ClassNotFoundException
    LineItem lineItem = new LineItem(name, quantity, priceInMicros, currencyCode);

    String expected = String.format("(item: %s, qty: %s, price: %.2f %s)", name, quantity, priceInMicros / 1000000d, currencyCode);

    String actual = lineItem.toString();

    assertEquals(expected, actual);
  }

}
